import {
  afterNextRender,
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  inject,
  viewChild,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '{{alias}}/utils';
import { HbCarouselComponent } from './carousel.component';

@Component({
  selector: 'hb-carousel-content, [hb-carousel-content]',
  template: `
    <div #viewport class="overflow-hidden">
      <div
        [class]="containerClasses()"
        [style.margin-left.px]="marginLeft()"
        [style.margin-top.px]="marginTop()"
      >
        <ng-content />
      </div>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[attr.data-slot]': "'carousel-content'" },
  exportAs: 'hbCarouselContent',
})
export class HbCarouselContentComponent {
  private readonly root = inject(HbCarouselComponent);
  private readonly viewport = viewChild.required<ElementRef<HTMLElement>>('viewport');

  protected readonly containerClasses = computed(() =>
    cn('flex', this.root.hbOrientation() === 'vertical' ? 'flex-col' : 'flex-row'),
  );
  protected readonly marginLeft = computed(() =>
    this.root.hbOrientation() === 'horizontal' ? -this.root.hbSpacing() : null,
  );
  protected readonly marginTop = computed(() =>
    this.root.hbOrientation() === 'vertical' ? -this.root.hbSpacing() : null,
  );

  constructor() {
    afterNextRender(() => this.root.initialize(this.viewport().nativeElement));
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbCarouselComponent } from './carousel.component';
import { carouselDotVariants } from './carousel.variants';

@Component({
  selector: 'hb-carousel-dots',
  template: `
    @for (snap of root.scrollSnaps(); track $index) {
      <button
        type="button"
        [class]="dotClass($index)"
        [attr.aria-label]="'Go to slide ' + ($index + 1)"
        [attr.aria-current]="root.selectedIndex() === $index"
        (click)="root.scrollTo($index)"
      ></button>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[class]': 'hostClasses()', '[attr.data-slot]': "'carousel-dots'" },
  exportAs: 'hbCarouselDots',
})
export class HbCarouselDotsComponent {
  protected readonly root = inject(HbCarouselComponent);
  readonly class = input<ClassValue>('');
  protected readonly hostClasses = computed(() =>
    cn('flex items-center justify-center gap-2', this.class()),
  );
  protected dotClass(index: number): string {
    return cn(
      carouselDotVariants({ size: this.root.hbSize(), active: this.root.selectedIndex() === index }),
    );
  }
}

import {
