import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  DestroyRef,
  effect,
  inject,
  input,
  numberAttribute,
  output,
  signal,
  untracked,
  ViewEncapsulation,
} from '@angular/core';
import EmblaCarousel, {
  type EmblaCarouselType,
  type EmblaOptionsType,
  type EmblaPluginType,
} from 'embla-carousel';
import Autoplay from 'embla-carousel-autoplay';

import { cn, type ClassValue } from '{{alias}}/utils';
import { type HbCarouselSize } from './carousel.variants';

@Component({
  selector: 'hb-carousel',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'hostClasses()',
    role: 'region',
    'aria-roledescription': 'carousel',
    '[attr.data-slot]': "'carousel'",
  },
  exportAs: 'hbCarousel',
})
export class HbCarouselComponent {
  readonly hbOrientation = input<'horizontal' | 'vertical'>('horizontal');
  readonly hbAlign = input<'start' | 'center' | 'end'>('start');
  readonly hbLoop = input(false, { transform: booleanAttribute });
  readonly hbDragFree = input(false, { transform: booleanAttribute });
  readonly hbSpacing = input(16, { transform: numberAttribute });
  readonly hbSize = input<HbCarouselSize>('md');
  readonly hbAutoplay = input(false, { transform: booleanAttribute });
  readonly hbDelay = input(4000, { transform: numberAttribute });
  readonly class = input<ClassValue>('');

  readonly hbSelect = output<number>();

  readonly api = signal<EmblaCarouselType | null>(null);
  readonly canScrollPrev = signal(false);
  readonly canScrollNext = signal(false);
  readonly selectedIndex = signal(0);
  readonly scrollSnaps = signal<number[]>([]);

  private readonly options = computed<EmblaOptionsType>(() => ({
    axis: this.hbOrientation() === 'vertical' ? 'y' : 'x',
    align: this.hbAlign(),
    loop: this.hbLoop(),
    dragFree: this.hbDragFree(),
    containScroll: 'trimSnaps',
  }));
  private buildPlugins(): EmblaPluginType[] {
    return this.hbAutoplay()
      ? [Autoplay({ delay: this.hbDelay(), stopOnMouseEnter: true, stopOnInteraction: false })]
      : [];
  }

  protected readonly hostClasses = computed(() => cn('relative', this.class()));

  constructor() {
    inject(DestroyRef).onDestroy(() => this.api()?.destroy());
    effect(() => {
      const opts = this.options();
      const autoplay = this.hbAutoplay();
      const delay = this.hbDelay();
      void autoplay;
      void delay;
      const api = untracked(() => this.api());
      api?.reInit(opts, this.buildPlugins());
    });
  }

  initialize(viewport: HTMLElement): void {
    const embla = EmblaCarousel(viewport, this.options(), this.buildPlugins());
    const update = (): void => {
      this.canScrollPrev.set(embla.canScrollPrev());
      this.canScrollNext.set(embla.canScrollNext());
      this.selectedIndex.set(embla.selectedScrollSnap());
      this.scrollSnaps.set(embla.scrollSnapList());
      this.hbSelect.emit(embla.selectedScrollSnap());
    };
    embla.on('select', update);
    embla.on('reInit', update);
    update();
    this.api.set(embla);
  }
  scrollPrev(): void {
    this.api()?.scrollPrev();
  }
  scrollNext(): void {
    this.api()?.scrollNext();
  }
  scrollTo(index: number): void {
    this.api()?.scrollTo(index);
  }
}

import { HbCarouselComponent } from './carousel.component';
import { HbCarouselContentComponent } from './carousel-content.component';
import { HbCarouselDotsComponent } from './carousel-dots.component';
import { HbCarouselItemComponent } from './carousel-item.component';
import { HbCarouselNextComponent } from './carousel-next.component';
import { HbCarouselPreviousComponent } from './carousel-previous.component';

export const HbCarouselImports = [
  HbCarouselComponent,
  HbCarouselContentComponent,
  HbCarouselItemComponent,
  HbCarouselPreviousComponent,
  HbCarouselNextComponent,
  HbCarouselDotsComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const carouselItemVariants = cva('min-w-0 shrink-0 grow-0 basis-full');

export const carouselNavVariants = cva(
  cn(
    'absolute z-10 inline-flex items-center justify-center rounded-full border border-input bg-background text-foreground shadow-xs transition-colors',
    'hover:bg-accent hover:text-accent-foreground disabled:pointer-events-none disabled:opacity-40 [&_ng-icon]:size-4',
  ),
  {
    variants: {
      size: { xs: 'size-6', sm: 'size-7', md: 'size-8', lg: 'size-9', xl: 'size-10' },
    },
    defaultVariants: { size: 'md' },
  },
);

export const carouselDotVariants = cva('rounded-full transition-colors', {
  variants: {
    size: { xs: 'size-1.5', sm: 'size-2', md: 'size-2.5', lg: 'size-3', xl: 'size-3.5' },
    active: { true: 'bg-primary', false: 'bg-muted-foreground/40 hover:bg-muted-foreground/70' },
  },
  defaultVariants: { size: 'md', active: false },
});

export type HbCarouselSize = NonNullable<VariantProps<typeof carouselNavVariants>['size']>;

export * from './carousel.component';
export * from './carousel-content.component';
export * from './carousel-item.component';
export * from './carousel-previous.component';
export * from './carousel-next.component';
export * from './carousel-dots.component';
export * from './carousel.variants';
export * from './carousel.imports';

